// ─── EXTRACT & NORMALISE TELEGRAM INPUT ───────────────────────────────────
const msg   = $input.first().json.message;
const text  = (msg.text || '').trim();
const chatId = String(msg.chat.id);
const userId = String(msg.from?.id ?? chatId);
const firstName = msg.from?.first_name ?? 'Customer';
const ts = msg.date ? new Date(msg.date * 1000).toISOString() : new Date().toISOString();

// ─── STATIC MOCK PRODUCT CATALOGUE (Shopify stand-in) ────────────────────
// Replace this array with a real HTTP node → Shopify Admin API call when live.
const PRODUCTS = [
  { id: 'P001', name: 'Hydra-Boost Serum',        type: 'serum',     concerns: ['dryness','dehydration','dull skin'],               price: 34.99, inStock: true,  description: 'Hyaluronic acid + ceramide serum for all-day moisture.' },
  { id: 'P002', name: 'Clear Skin Niacinamide Toner', type: 'toner',  concerns: ['oily skin','large pores','uneven texture','acne'],  price: 22.50, inStock: true,  description: '10% Niacinamide toner that minimises pores and controls sebum.' },
  { id: 'P003', name: 'Vitamin C Brightening Cream',  type: 'cream',  concerns: ['hyperpigmentation','dark spots','dull skin','aging'], price: 45.00, inStock: true,  description: '15% stable Vitamin C for radiance and UV-damage correction.' },
  { id: 'P004', name: 'SPF 50 Mineral Sunscreen',     type: 'sunscreen', concerns: ['sun protection','sensitive skin','acne'],         price: 28.00, inStock: true,  description: 'Zinc-oxide mineral SPF suitable for sensitive and acne-prone skin.' },
  { id: 'P005', name: 'Retinol Night Renewal Cream',  type: 'cream',  concerns: ['aging','fine lines','wrinkles','dark spots'],       price: 52.00, inStock: false, description: '0.3% encapsulated retinol for overnight cell turnover.' },
  { id: 'P006', name: 'Soothing Centella Gel Cream',  type: 'cream',  concerns: ['redness','sensitivity','rosacea','irritation'],    price: 31.00, inStock: true,  description: 'Centella asiatica + panthenol to calm reactive skin.' },
  { id: 'P007', name: 'AHA/BHA Exfoliating Cleanser', type: 'cleanser', concerns: ['acne','congestion','dull skin','oily skin'],      price: 19.00, inStock: true,  description: 'Gentle chemical exfoliant with 5% AHA and 2% BHA.' },
  { id: 'P008', name: 'Peptide Eye Serum',            type: 'serum',  concerns: ['fine lines','dark circles','aging','puffiness'],   price: 38.00, inStock: true,  description: 'Multi-peptide + caffeine eye serum for visible de-aging.' }
];

// ─── HUMAN-ESCALATION KEYWORDS ───────────────────────────────────────────
const ESCALATION_KEYWORDS = [
  'allergic reaction', 'bad reaction',
  'lawsuit'
];

const needsHuman = ESCALATION_KEYWORDS.some(kw => text.toLowerCase().includes(kw));

// ─── CONVERSATION HISTORY (Stored in workflow static data) ───────────────
// n8n static data persists per-workflow. Key = userId.
const workflowData = $getWorkflowStaticData('global');
if (!workflowData.conversations) workflowData.conversations = {};
const history = workflowData.conversations[userId] ?? [];

// Append user message to history
history.push({ role: 'user', content: text, ts });
// Keep last 20 messages to manage token usage
const trimmedHistory = history.slice(-20);
workflowData.conversations[userId] = trimmedHistory;

// ─── BUILD COMPACT CATALOGUE SUMMARY FOR PROMPT ──────────────────────────
const catalogueSummary = PRODUCTS.map(p =>
  `[${p.id}] ${p.name} | ${p.type} | $${p.price} | ${p.inStock ? 'In Stock' : 'OUT OF STOCK'} | Targets: ${p.concerns.join(', ')} | ${p.description}`
).join('\n');

return [{
  json: {
    chatId,
    userId,
    firstName,
    userMessage: text,
    ts,
    needsHuman,
    conversationHistory: trimmedHistory,
    catalogueSummary,
    products: PRODUCTS
  }
}];

const d = $input.first().json;
const upstream = $('Prompt Builder').first().json;

const parsed = {
  reply:               d.reply || "Sorry, I had trouble with that. Let me get someone to help.",
  escalate:            d.escalate ?? false,
  escalationReason:    d.escalationReason ?? '',
  recommendedProducts: d.recommendedProducts ?? [],
  intent:              d.intent ?? 'general_query'
};

const workflowData = $getWorkflowStaticData('global');
const userId = upstream.userId;
if (workflowData.conversations?.[userId]) {
  workflowData.conversations[userId].push({
    role: 'assistant',
    content: parsed.reply,
    ts: new Date().toISOString()
  });
  workflowData.conversations[userId] = workflowData.conversations[userId].slice(-20);
}

return [{
  json: {
    chatId:              upstream.chatId,
    userId:              upstream.userId,
    firstName:           upstream.firstName,
    reply:               parsed.reply,
    escalate:            parsed.escalate ?? false,
    escalationReason:    parsed.escalationReason ?? '',
    recommendedProducts: parsed.recommendedProducts ?? [],
    intent:              parsed.intent ?? 'general_query',
    readyToHandoff:      parsed.escalate === true && parsed.escalationReason !== ''
  }
}];

// ─── BUILD HUMAN ESCALATION ALERT ───────────────────────────────────────
const d = $input.first().json;

const alertMessage = [
  `🚨 <b>Human Agent Required</b>`,
  ``,
  `<b>Customer:</b> ${d.firstName} (ID: ${d.userId})`,
  `<b>Chat ID:</b> ${d.chatId}`,
  `<b>Intent:</b> ${d.intent ?? 'N/A'}`,
  `<b>Reason:</b> ${d.escalationReason || d.userMessage || 'Customer requested human'}`,
  ``,
  `<b>Customer Message:</b>`,
  d.userMessage ?? '(see chat)',
  ``,
  `Reply directly to this chat: <code>${d.chatId}</code>`
].join('\n');

// Customer-facing acknowledgement
const customerAck = [
  `Hi ${d.firstName} 👋`,
  ``,
  `I've flagged your message and a member of our team will be with you shortly.`,
  `In the meantime, feel free to browse our skincare guides at [YOUR WEBSITE].`,
  ``,
  `Thank you for your patience! 💚`
].join('\n');

return [{
  json: {
    ...d,
    alertMessage,
    customerAck
  }
}];

