const d = $input.first().json;

const ackMessages = {
  damaged: `Hi ${d.firstName} 👋\n\nI'm really sorry to hear about your damaged package — that's not the experience we want for you.\n\nI've flagged this with our team and someone will be in touch shortly to make it right. 💚`,
  refund: `Hi ${d.firstName} 👋\n\nThank you for reaching out. I've passed your request to our team and they'll be with you shortly to sort this out.`,
  complaint: `Hi ${d.firstName} 👋\n\nI'm sorry your experience didn't meet expectations. A team member will be with you shortly to help resolve this.`,
  human_request: `Hi ${d.firstName} 👋\n\nOf course! I've notified our team and someone will be with you shortly. 💚`,
  default: `Hi ${d.firstName} 👋\n\nI've flagged your message and a member of our team will be with you shortly.\n\nThank you for your patience! 💚`
};

const reason = (d.escalationReason || '').toLowerCase();
const DAMAGE_WORDS   = ['damage', 'broken', 'arrived', 'packaging', 'leaking', 'spill'];
const REFUND_WORDS   = ['refund', 'return', 'money back', 'charge', 'payment'];
const COMPLAINT_WORDS = ['complaint', 'unhappy', 'disappointed', 'experience', 'wrong item', 'missing'];
const HUMAN_WORDS    = ['speak to', 'talk to', 'human', 'agent', 'person'];

const matches = (words) => words.some(w => reason.includes(w));

const triggered = [];
if (matches(DAMAGE_WORDS))    triggered.push('damaged package');
if (matches(REFUND_WORDS))    triggered.push('refund request');
if (matches(COMPLAINT_WORDS)) triggered.push('complaint');
if (matches(HUMAN_WORDS))     triggered.push('request');

const concernSummary = triggered.length > 0
  ? triggered.join(' and ')
  : null;

const ack = concernSummary
  ? `Hi ${d.firstName} 👋\n\nI'm sorry to hear about your ${concernSummary}. I've flagged this with our team and someone will be in touch shortly to help resolve everything for you. 💚`
  : ackMessages.default;

return [{ json: { ...d, customerAck: ack } }];

const raw = $input.first().json.output || '';
const str = typeof raw === 'object' ? JSON.stringify(raw) : String(raw);

const extract = (tag, text) => {
  const match = text.match(new RegExp(`<${tag}>([\\s\\S]*?)<\\/${tag}>`));
  return match ? match[1].trim() : '';
};

const reply             = extract('reply', str);
const escalate          = extract('escalate', str) === 'true';
const escalationReason  = extract('escalationReason', str);
const productsRaw       = extract('recommendedProducts', str);
const recommendedProducts = productsRaw
  ? productsRaw.split(',').map(p => p.trim()).filter(Boolean)
  : [];
const intent            = extract('intent', str) || 'general_query';

return [{
  json: {
    ...($input.first().json),
    reply,
    escalate,
    escalationReason,
    recommendedProducts,
    intent,
    readyToHandoff: escalate === true && escalationReason !== ''
  }
}];

